/**
 * KYC Service
 * 
 * Handles KYC document upload and retrieval for both individual users and
 * business accounts. Manages document submission for verification processes
 * and retrieves existing KYC document status.
 */

import { apiRequest } from '@/shared/services/apiClient.js';
import logger from '@/shared/utils/logger.js';

export const kycService = {
  async getKYCDocuments() {
    logger.debug('Fetching KYC documents');

    const kycData = await apiRequest('/auth/profile/kyc-docs/', {
      method: 'GET',
    });

    logger.debug('KYC documents fetched');
    return kycData;
  },

  async uploadKYCDocument(formData) {
    logger.debug('Uploading KYC document');

    const uploadData = await apiRequest('/auth/profile/kyc-docs', {
      method: 'POST',
      body: formData,
    });

    logger.debug('KYC document uploaded successfully');
    return uploadData;
  },
  async getBusinessKYCDocuments(businessId) {
    logger.debug('Fetching business KYC documents');
  
    const kycData = await apiRequest(`/auth/business/${businessId}/documents/`, {
      method: 'GET',
    });
  
    logger.debug('Business KYC documents fetched');
    return kycData;
  },
  
  async uploadBusinessKYCDocument(businessId, formData) {
    logger.debug('Uploading business KYC document');
  
    const uploadData = await apiRequest(`/auth/business/${businessId}/documents`, {
      method: 'POST',
      body: formData,
    });
  
    logger.debug('Business KYC document uploaded successfully');
    return uploadData;
  },

  async getBusinessVerificationLevel(businessId) {
    if (!businessId) {
      throw new Error('Business ID is required to fetch business verification level');
    }

    logger.debug('Fetching business verification level');

    const data = await apiRequest(`/auth/business/${businessId}/get-verification-level`, {
      method: 'GET',
      headers: {
        'X-Skip-Refresh': '1'
      }
    });

    logger.debug('Business verification level fetched');
    return data;
  },
};

export default kycService;